 {"id":"flywheel_gateway-7ek","title":"Audit Trail Hardening","description":"## Background

advanced customers require comprehensive audit logging for compliance (SOC 2, HIPAA, GDPR), security forensics, and operational troubleshooting. A robust audit trail provides an immutable record of all significant actions within the system, enabling organizations to answer "who did what, when, and why" for any point in time.

## Problem Statement

Current logging is inconsistent across services, lacks correlation IDs for request tracing, may inadvertently log sensitive data, and has no standardized export or retention policies. This creates compliance gaps and makes incident investigation difficult. Organizations cannot demonstrate to auditors that they have complete visibility into system access and changes.

## Technical Approach

### Audit Event Structure

```typescript
// apps/gateway/src/types/audit.types.ts

interface AuditEvent {
  // Identification
  id: string; // UUID
  correlationId: string; // Request correlation ID
  parentEventId?: string; // For nested operations

  // Timing
  timestamp: Date;
  duration?: number; // Operation duration in ms

  // Actor information
  actor: {
    type: 'user' | 'agent' | 'system' | 'api_key';
    id: string;
    name?: string;
    email?: string;
    ip?: string;
    userAgent?: string;
    sessionId?: string;
  };

  // Organization context
  org: {
    id: string;
    name?: string;
  };

  // Action details
  action: AuditAction;
  resource: {
    type: ResourceType;
    id: string;
    name?: string;
    parentId?: string;
    parentType?: string;
  };

  // Operation details
  operation: {
    type: 'create' | 'read' | 'update' | 'delete' | 'execute' | 'login' | 'logout';
    status: 'success' | 'failure' | 'partial';
    errorCode?: string;
    errorMessage?: string;
  };

  // Change tracking
  changes?: {
    before?: Record<string, any>; // Redacted
    after?: Record<string, any>; // Redacted
    diff?: Array<{ field: string; old: any; new: any }>;
  };

  // Additional context
  metadata: {
    requestId: string;
    endpoint?: string;
    method?: string;
    sourceService?: string;
    tags?: string[];
    [key: string]: any;
  };
}

type AuditAction = 
  // Authentication
  | 'auth.login'
  | 'auth.logout'
  | 'auth.login_failed'
  | 'auth.password_changed'
  | 'auth.mfa_enabled'
  | 'auth.mfa_disabled'
  | 'auth.api_key_created'
  | 'auth.api_key_revoked'

  // User management
  | 'user.created'
  | 'user.updated'
  | 'user.deleted'
  | 'user.role_changed'
  | 'user.invited'

  // Agent operations
  | 'agent.created'
  | 'agent.updated'
  | 'agent.deleted'
  | 'agent.started'
  | 'agent.stopped'
  | 'agent.config_changed'
  | 'agent.execution'

  // Bead operations
  | 'bead.created'
  | 'bead.updated'
  | 'bead.deleted'
  | 'bead.status_changed'
  | 'bead.assigned'

  // Conflict operations
  | 'conflict.detected'
  | 'conflict.resolved'
  | 'conflict.escalated'

  // Settings changes
  | 'settings.updated'
  | 'integration.connected'
  | 'integration.disconnected'

  // Data access
  | 'data.exported'
  | 'data.accessed'
  | 'report.generated';

type ResourceType = 
  | 'user' | 'team' | 'organization'
  | 'agent' | 'bead' | 'conflict'
  | 'dashboard' | 'pipeline'
  | 'api_key' | 'integration'
  | 'settings' | 'export';
```

### Correlation ID Propagation

```typescript
// apps/gateway/src/middleware/correlation.middleware.ts

import { v4 as uuidv4 } from 'uuid';
import { AsyncLocalStorage } from 'async_hooks';

// AsyncLocalStorage for request-scoped correlation
const correlationStorage = new AsyncLocalStorage<CorrelationContext>();

interface CorrelationContext {
  correlationId: string;
  parentSpanId?: string;
  traceId?: string;
  requestId: string;
}

export function correlationMiddleware(req: Request, res: Response, next: NextFunction) {
  // Extract or generate correlation ID
  const correlationId = 
    req.headers['x-correlation-id'] as string ||
    req.headers['x-request-id'] as string ||
    uuidv4();

  const context: CorrelationContext = {
    correlationId,
    traceId: req.headers['x-trace-id'] as string,
    parentSpanId: req.headers['x-parent-span-id'] as string,
    requestId: uuidv4(),
  };

  // Set response header for client correlation
  res.setHeader('x-correlation-id', correlationId);
  res.setHeader('x-request-id', context.requestId);

  // Run request in correlation context
  correlationStorage.run(context, () => next());
}

export function getCorrelationContext(): CorrelationContext | undefined {
  return correlationStorage.getStore();
}

// Propagate to external service calls
export function getCorrelationHeaders(): Record<string, string> {
  const context = getCorrelationContext();
  if (!context) return {};

  return {
    'x-correlation-id': context.correlationId,
    'x-request-id': context.requestId,
    'x-trace-id': context.traceId || context.correlationId,
  };
}
```

### Sensitive Data Redaction

```typescript
// apps/gateway/src/services/audit-redaction.service.ts

interface RedactionConfig {
  // Fields to completely remove
  removeFields: string[];

  // Fields to mask (show partial)
  maskFields: {
    field: string;
    pattern: 'email' | 'phone' | 'card' | 'ssn' | 'api_key' | 'custom';
    customMask?: (value: string) => string;
  }[];

  // Fields to hash (for later matching without exposing)
  hashFields: string[];

  // Regex patterns to redact in any string field
  redactPatterns: RegExp[];
}

const defaultRedactionConfig: RedactionConfig = {
  removeFields: [
    'password',
    'passwordHash',
    'secret',
    'privateKey',
    'accessToken',
    'refreshToken',
    'sessionToken',
    'creditCard',
    'cvv',
    'ssn',
  ],

  maskFields: [
    { field: 'email', pattern: 'email' },  // j***@example.com
    { field: 'phone', pattern: 'phone' },  // ***-***-1234
    { field: 'apiKey', pattern: 'api_key' }, // sk_...***xyz
  ],

  hashFields: [
    'userId', // Can verify matches without exposing
  ],

  redactPatterns: [
    /Bearer\s+[A-Za-z0-9\-._~+\/]+=*/g,  // JWT tokens
    /sk_[a-zA-Z0-9]{32,}/g,              // API keys
  ],
};

class AuditRedactionService {
  redact(data: any, config = defaultRedactionConfig): any {
    if (!data) return data;
    if (typeof data === 'string') return this.redactString(data, config);
    if (Array.isArray(data)) return data.map(item => this.redact(item, config));
    if (typeof data === 'object') return this.redactObject(data, config);
    return data;
  }

  private applyMask(value: string, pattern: string): string {
    switch (pattern) {
      case 'email':
        const [local, domain] = value.split('@');
        return local[0] + '***@' + domain;
      case 'phone':
        return value.replace(/\d(?=\d{4})/g, '*');
      case 'api_key':
        return value.slice(0, 5) + '***' + value.slice(-3);
      default:
        return '***';
    }
  }
}
```

### Export Functionality

```typescript
// apps/gateway/src/services/audit-export.service.ts

interface ExportOptions {
  format: 'csv' | 'json' | 'json_lines';
  dateRange: { start: Date; end: Date };
  filters?: AuditFilter;
  includeFields?: string[];
  excludeFields?: string[];
  compression?: 'none' | 'gzip' | 'zip';
}

interface AuditFilter {
  actions?: AuditAction[];
  actors?: string[];
  resources?: { type: ResourceType; id?: string }[];
  status?: ('success' | 'failure')[];
  searchQuery?: string;
}

class AuditExportService {
  async exportToFile(options: ExportOptions): Promise<ExportResult> {
    // Stream-based export for large datasets
    const stream = this.createExportStream(options);
    const filename = this.generateFilename(options);

    // Write to temporary file
    const tempPath = await this.writeStreamToFile(stream, filename, options.compression);

    // Generate signed download URL
    const downloadUrl = await this.uploadToStorage(tempPath);

    // Audit the export itself
    await this.auditService.log({
      action: 'data.exported',
      resource: { type: 'export', id: filename },
      metadata: {
        format: options.format,
        dateRange: options.dateRange,
        recordCount: stream.recordCount,
      },
    });

    return {
      filename,
      downloadUrl,
      expiresAt: new Date(Date.now() + 24 * 60 * 60 * 1000), // 24 hours
      recordCount: stream.recordCount,
      fileSize: stream.byteCount,
    };
  }
}
```

### Retention Policies

```typescript
// apps/gateway/src/services/audit-retention.service.ts

interface RetentionPolicy {
  id: string;
  name: string;
  description?: string;

  // What to retain
  filter: {
    actions?: AuditAction[];
    severities?: string[];
    resourceTypes?: ResourceType[];
  };

  // How long to retain
  retention: {
    duration: number; // Days
    archiveFirst: boolean; // Archive to cold storage before delete
    archiveLocation?: string; // S3 bucket/path
  };

  // When created/modified
  createdAt: Date;
  updatedAt: Date;
  createdBy: string;
}

const defaultPolicies: RetentionPolicy[] = [
  {
    id: 'auth-events',
    name: 'Authentication Events',
    filter: { actions: ['auth.login', 'auth.logout', 'auth.login_failed'] },
    retention: { duration: 365, archiveFirst: true },
  },
  {
    id: 'data-access',
    name: 'Data Access Events',
    filter: { actions: ['data.accessed', 'data.exported'] },
    retention: { duration: 730, archiveFirst: true }, // 2 years
  },
  {
    id: 'config-changes',
    name: 'Configuration Changes',
    filter: { actions: ['settings.updated', 'agent.config_changed'] },
    retention: { duration: 365, archiveFirst: true },
  },
  {
    id: 'default',
    name: 'Default Policy',
