## Database Schema

```sql
-- Primary audit log table
CREATE TABLE audit_events (
  id UUID PRIMARY KEY,
  correlation_id UUID NOT NULL,
  parent_event_id UUID REFERENCES audit_events(id),
  timestamp TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  duration_ms INTEGER,

  -- Actor
  actor_type VARCHAR(50) NOT NULL,
  actor_id VARCHAR(255) NOT NULL,
  actor_ip INET,
  actor_user_agent TEXT,

  -- Organization
  org_id UUID NOT NULL REFERENCES organizations(id),

  -- Action
  action VARCHAR(100) NOT NULL,
  resource_type VARCHAR(50) NOT NULL,
  resource_id VARCHAR(255),

  -- Operation
  operation_type VARCHAR(20) NOT NULL,
  operation_status VARCHAR(20) NOT NULL,
  error_code VARCHAR(50),
  error_message TEXT,

  -- Changes (JSONB for flexibility)
  changes JSONB,

  -- Metadata
  metadata JSONB NOT NULL DEFAULT '{}'
);

-- Indexes for common query patterns
CREATE INDEX idx_audit_correlation ON audit_events(correlation_id);
CREATE INDEX idx_audit_org_time ON audit_events(org_id, timestamp DESC);
CREATE INDEX idx_audit_actor ON audit_events(actor_id, timestamp DESC);
CREATE INDEX idx_audit_action ON audit_events(action, timestamp DESC);
CREATE INDEX idx_audit_resource ON audit_events(resource_type, resource_id, timestamp DESC);
```

## Dependencies

- @clickhouse/client: ClickHouse integration
